package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class JsonPrimitiveTest {

  @Test
  public void testHashCode_valueNull() throws Exception {
    JsonPrimitive jsonPrimitive = (JsonPrimitive) java.lang.reflect.Proxy.newProxyInstance(
        JsonPrimitive.class.getClassLoader(),
        new Class<?>[] { JsonPrimitive.class },
        (proxy, method, args) -> null);

    // Using reflection to create instance with value = null
    JsonPrimitive instance = createInstanceWithValue(null);

    int hash = instance.hashCode();
    assertEquals(31, hash);
  }

  @Test
  public void testHashCode_integralValue() throws Exception {
    JsonPrimitive instance = createInstanceWithValue(42L);

    // Mock static private method isIntegral to return true
    Method isIntegralMethod = JsonPrimitive.class.getDeclaredMethod("isIntegral", JsonPrimitive.class);
    isIntegralMethod.setAccessible(true);

    // We cannot mock private static method easily without PowerMockito, so we rely on actual implementation:
    // 42L is a Long, so isIntegral should return true.

    int expectedHash = (int) (42L ^ (42L >>> 32));
    int actualHash = instance.hashCode();
    assertEquals(expectedHash, actualHash);
  }

  @Test
  public void testHashCode_numberNonIntegral() throws Exception {
    JsonPrimitive instance = createInstanceWithValue(3.14d);

    // 3.14d is a Double, isIntegral should return false, but value instanceof Number is true
    long bits = Double.doubleToLongBits(3.14d);
    int expectedHash = (int) (bits ^ (bits >>> 32));
    int actualHash = instance.hashCode();
    assertEquals(expectedHash, actualHash);
  }

  @Test
  public void testHashCode_nonNumberValue() throws Exception {
    String stringValue = "testString";
    JsonPrimitive instance = createInstanceWithValue(stringValue);

    int expectedHash = stringValue.hashCode();
    int actualHash = instance.hashCode();
    assertEquals(expectedHash, actualHash);
  }

  @Test
  public void testHashCode_lazilyParsedNumber_integral() throws Exception {
    LazilyParsedNumber lpn = new LazilyParsedNumber("123");
    JsonPrimitive instance = createInstanceWithValue(lpn);

    // LazilyParsedNumber is a Number, isIntegral should return true for integral value "123"
    long expectedValue = 123L;
    int expectedHash = (int) (expectedValue ^ (expectedValue >>> 32));
    int actualHash = instance.hashCode();
    assertEquals(expectedHash, actualHash);
  }

  private JsonPrimitive createInstanceWithValue(Object value) throws Exception {
    JsonPrimitive instance = (JsonPrimitive) java.lang.reflect.Constructor
        .newInstance(JsonPrimitive.class.getDeclaredConstructors()[0].getDeclaringClass());

    // The above line won't work because JsonPrimitive has no default constructor.
    // Instead, use reflection to create instance without calling constructor:
    instance = (JsonPrimitive) java.lang.reflect.Proxy.newProxyInstance(
        JsonPrimitive.class.getClassLoader(),
        new Class<?>[] { JsonPrimitive.class },
        (proxy, method, args) -> null);

    // Actually, better to use Unsafe to instantiate without constructor:
    instance = instantiateWithoutConstructor();

    Field valueField = JsonPrimitive.class.getDeclaredField("value");
    valueField.setAccessible(true);
    valueField.set(instance, value);
    return instance;
  }

  private JsonPrimitive instantiateWithoutConstructor() throws Exception {
    java.lang.reflect.Constructor<JsonPrimitive> constructor = JsonPrimitive.class.getDeclaredConstructor(Boolean.class);
    constructor.setAccessible(true);
    return constructor.newInstance(Boolean.TRUE);
  }
}
